args.sparql:
SELECT ?characterLabel WHERE {
  VALUES ?movie { wd:Q131864 wd:Q15632949 }
  ?movie p:P161 ?statement .
  ?statement ps:P161 wd:Q229775 ;
             pq:P451 ?character .
  ?character rdfs:label ?characterLabel .
  FILTER(LANG(?characterLabel) = "en")
}

SELECT ?character WHERE {
  VALUES ?movie { wd:Q15632949 }
  ?movie p:P161 ?statement .
  ?statement ps:P161 wd:Q229775 ;
             pq:P451 ?character .
}

SELECT ?movie ?movieLabel WHERE {
  ?movie wdt:P161 wd:Q229775 .
  ?movie rdfs:label ?movieLabel .
  FILTER(LANG(?movieLabel) = "en")
} LIMIT 10

SELECT ?role WHERE {
  wd:Q131864 p:P161 ?cast .
  ?cast ps:P161 wd:Q229775 ;
        pq:P1477 ?role .
}

SELECT ?role WHERE {
  wd:Q131864 p:P161 ?cast .
  ?cast ps:P161 wd:Q229775 .
  ?cast ?qualifier ?role .
  FILTER(?qualifier != ps:P161)
}
